import "bootstrap";
import "../node_modules/bootstrap/dist/css/bootstrap.min.css";
import "./App.scss";

import React, { Component } from "react";
import { Route, BrowserRouter as Router, Switch } from "react-router-dom";

import About from "./pages/About/About";
import Card from "./parts/Card/Card";
import Home from "./pages/Home/Home";
import Navbar from "./parts/Navbar/Navbar";
import ReactGA from "react-ga";
import Redirect from "./components/Redirect/Redirect";
import moveBackgroundPositionOnMouseMove from "./utils/moveBackgroundPositionOnMouseMove";

interface State {
  bgStyle: {
    backgroundPosition: string;
  };
  path: string;
}

class App extends Component {
  state: State = {
    bgStyle: {
      backgroundPosition: "",
    },
    path: "",
  };

  componentDidMount(): void {
    window.addEventListener("mousemove", this.setBackgroundPosition.bind(this));
  }

  componentDidUpdate(): void {
    const path = window.location.pathname + window.location.search;
    if (this.state.path === path) return;
    this.setState({ ...this.state, path });
    ReactGA.pageview(path);
  }

  setBackgroundPosition(event: MouseEvent): void {
    if (document.body.clientWidth <= 992) return;
    this.setState({
      bgStyle: {
        backgroundPosition: moveBackgroundPositionOnMouseMove(event),
      },
    });
  }

  render(): JSX.Element {
    const { bgStyle } = this.state;

    return (
      <div id='app'>
        <div id='bg' className='d-none d-lg-block'></div>
        <div id='bg-back' style={bgStyle} className='d-none d-lg-block'></div>
        <Router>
          <Card>
            <Navbar />
            <Switch>
              <Route path='/' exact component={Home} />
              <Route path='/about' component={About} />
              <Route
                path='/github'
                component={() => <Redirect url='https://github.com/ahmet-cetinkaya' />}
              />
              <Route
                path='/linkedin'
                component={() => <Redirect url='https://www.linkedin.com/in/ahmet-cetinkaya' />}
              />
              <Route
                path='/behance'
                component={() => <Redirect url='https://www.behance.net/ahmetcetinkaya' />}
              />
              <Route
                path='/itch'
                component={() => <Redirect url='https://ahmetcetinkaya.itch.io' />}
              />
              <Route
                path='/twitter'
                component={() => <Redirect url='https://twitter.com/ahmet4cetinkaya' />}
              />
              <Route
                path='/instagram'
                component={() => <Redirect url='https://www.instagram.com/ahmet4cetinkaya' />}
              />
              <Route
                path='/discord'
                component={() => <Redirect url='https://discordapp.com/users/248840559039348736' />}
              />
              <Route
                path='/steam'
                component={() => <Redirect url='https://steamcommunity.com/id/J4UNE' />}
              />
            </Switch>
          </Card>
        </Router>
      </div>
    );
  }
}

export default App;
